#!/usr/bin/env node
/**
 * check-env-leak.mjs — pre-commit guard.
 *
 * Blocks any commit that stages an .env / .env.local file. The root .env
 * lives outside git; per-project .env.local files are generated by
 * sync-env.mjs and gitignored. If you see this script reject a commit, it
 * means a real .env file is about to land in version control — that's a
 * secret leak.
 *
 * Allowed (no leak): .env.example files (no real values).
 *
 * INSTALL: enabled via husky-free pre-commit using simple-git-hooks or
 * called directly from `.git/hooks/pre-commit` (see HOOKS.md).
 */
import { execSync } from 'node:child_process';

function stagedFiles() {
  try {
    const out = execSync('git diff --cached --name-only --diff-filter=ACMR', { encoding: 'utf-8' });
    return out.split('\n').map((s) => s.trim()).filter(Boolean);
  } catch {
    return [];
  }
}

function isForbidden(path) {
  // Allow .env.example files
  if (/\.env\.example$/i.test(path)) return false;
  // Block any other .env / .env.local / .env.<anything>
  if (/(^|\/)\.env(\.local)?(\.[^/]+)?$/i.test(path)) return true;
  return false;
}

function main() {
  const staged = stagedFiles();
  const offending = staged.filter(isForbidden);

  if (offending.length === 0) {
    process.exit(0);
  }

  console.error('\n✗ commit blocked: secret env files staged');
  for (const f of offending) console.error(`    ${f}`);
  console.error('\nThis monorepo uses a single root .env + `pnpm sync:env` to fan out');
  console.error('per-project .env.local files (all gitignored). Don\'t commit any of them.');
  console.error('\nIf you intended to commit a TEMPLATE, rename to <name>.example and re-stage.');
  console.error('If this is a false positive (e.g. you renamed a file), reset and re-stage.\n');
  process.exit(1);
}

main();
